import{_ as e,c as s,o as t,ae as i}from"./chunks/framework.B7Y1jjX-.js";const l=JSON.parse('{"title":"2.1 数据的表示","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/学习/408/计算机组成原理/第二章 计算机的数据.md","filePath":"generated-notes/学习/408/计算机组成原理/第二章 计算机的数据.md"}'),n={name:"generated-notes/学习/408/计算机组成原理/第二章 计算机的数据.md"};function r(d,a,p,h,g,o){return t(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="_2-1-数据的表示" tabindex="-1">2.1 数据的表示 <a class="header-anchor" href="#_2-1-数据的表示" aria-label="Permalink to &quot;2.1 数据的表示&quot;">​</a></h1><h2 id="_2-1-1-进位计数制" tabindex="-1">2.1.1 进位计数制 <a class="header-anchor" href="#_2-1-1-进位计数制" aria-label="Permalink to &quot;2.1.1 进位计数制&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112172818.png">查看图片：Pasted image 20251112172818.png</a> 基数：内个数码位所用到的符号的数量，r进制的基数为r</p><h3 id="位权展开法-转为十进制" tabindex="-1">位权展开法（转为十进制） <a class="header-anchor" href="#位权展开法-转为十进制" aria-label="Permalink to &quot;位权展开法（转为十进制）&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112172942.png">查看图片：Pasted image 20251112172942.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112173120.png">查看图片：Pasted image 20251112173120.png</a></p><h3 id="二八十六进制互转" tabindex="-1">二八十六进制互转 <a class="header-anchor" href="#二八十六进制互转" aria-label="Permalink to &quot;二八十六进制互转&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112173351.png">查看图片：Pasted image 20251112173351.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112173438.png">查看图片：Pasted image 20251112173438.png</a></p><h3 id="除基取余法-十进制转任意进制" tabindex="-1">除基取余法（十进制转任意进制） <a class="header-anchor" href="#除基取余法-十进制转任意进制" aria-label="Permalink to &quot;除基取余法（十进制转任意进制）&quot;">​</a></h3><p>除二倒取余： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112174326.png">查看图片：Pasted image 20251112174326.png</a></p><h3 id="乘基取整法" tabindex="-1">乘基取整法 <a class="header-anchor" href="#乘基取整法" aria-label="Permalink to &quot;乘基取整法&quot;">​</a></h3><p>乘二正取整： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112174629.png">查看图片：Pasted image 20251112174629.png</a> 0.2与0.3无法使用二进制精确的表示，是因为没有2^x的组合能够拼出这两个数，只能无限的接近，一般取到小数点第五位</p><h3 id="真值与机器数" tabindex="-1">真值与机器数 <a class="header-anchor" href="#真值与机器数" aria-label="Permalink to &quot;真值与机器数&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112174952.png">查看图片：Pasted image 20251112174952.png</a></p><h2 id="_2-1-2-定点数的编码表示" tabindex="-1">2.1.2 定点数的编码表示 <a class="header-anchor" href="#_2-1-2-定点数的编码表示" aria-label="Permalink to &quot;2.1.2 定点数的编码表示&quot;">​</a></h2><h3 id="无符号数" tabindex="-1">无符号数 <a class="header-anchor" href="#无符号数" aria-label="Permalink to &quot;无符号数&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112175953.png">查看图片：Pasted image 20251112175953.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112180022.png">查看图片：Pasted image 20251112180022.png</a> 通常讨论无符号数时，只会讨论整数</p><h3 id="有符号数" tabindex="-1">有符号数 <a class="header-anchor" href="#有符号数" aria-label="Permalink to &quot;有符号数&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112180327.png">查看图片：Pasted image 20251112180327.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112183104.png">查看图片：Pasted image 20251112183104.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112182404.png">查看图片：Pasted image 20251112182404.png</a></p><ul><li><p>原码： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112180910.png">查看图片：Pasted image 20251112180910.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112181255.png">查看图片：Pasted image 20251112181255.png</a></p></li><li><p>反码：与原码一一对应 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112181409.png">查看图片：Pasted image 20251112181409.png</a></p></li><li><p>补码： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112182058.png">查看图片：Pasted image 20251112182058.png</a> 由[x]补求[-x]补：符号位与数值为全部取反，末尾再+1 由补码求原码的快速运算：符号位不变，从右向左找到第一个“1”，将这个“1”左侧剩余的尾数取反，即可得到源码。用尾数取反+1也是一样的</p></li><li><p>移码：可以使用移码的值来比较真值的大小 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251112182235.png">查看图片：Pasted image 20251112182235.png</a></p></li></ul><h2 id="_2-1-2-码的作用" tabindex="-1">2.1.2 码的作用 <a class="header-anchor" href="#_2-1-2-码的作用" aria-label="Permalink to &quot;2.1.2 码的作用&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113164652.png">查看图片：Pasted image 20251113164652.png</a> 在使用有符号数的原码进行运算的时候（+-），必须要考虑数的正负，否则计算的结果会有异常，我们可以使用模运算将两个数的减法变为加法</p><h3 id="模运算" tabindex="-1">模运算 <a class="header-anchor" href="#模运算" aria-label="Permalink to &quot;模运算&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113165627.png">查看图片：Pasted image 20251113165627.png</a></p><p>由于模运算的性质，实质上是将数分为不同的类，上例中分为12类，而在字长为8bit的计算机中，是将数分为了2^8 类，也就是8位的计算机会自动的进行mod2^8的操作： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113170453.png">查看图片：Pasted image 20251113170453.png</a> 补码，也就是原码的补数，通过这样的方式就能仅在ALU中实现加法操作</p><h2 id="_2-1-4-c语言中的类型转换" tabindex="-1">2.1.4 C语言中的类型转换 <a class="header-anchor" href="#_2-1-4-c语言中的类型转换" aria-label="Permalink to &quot;2.1.4 C语言中的类型转换&quot;">​</a></h2><p>在计算机中，有符号定点整数通常是使用补码来表示的 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113171927.png">查看图片：Pasted image 20251113171927.png</a></p><h3 id="零扩展与符号扩展" tabindex="-1">零扩展与符号扩展 <a class="header-anchor" href="#零扩展与符号扩展" aria-label="Permalink to &quot;零扩展与符号扩展&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113172127.png">查看图片：Pasted image 20251113172127.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113173137.png">查看图片：Pasted image 20251113173137.png</a></p><h1 id="_2-2-数据的运算" tabindex="-1">2.2 数据的运算 <a class="header-anchor" href="#_2-2-数据的运算" aria-label="Permalink to &quot;2.2 数据的运算&quot;">​</a></h1><h2 id="_2-2-0-电路" tabindex="-1">2.2.0 电路 <a class="header-anchor" href="#_2-2-0-电路" aria-label="Permalink to &quot;2.2.0 电路&quot;">​</a></h2><p>优先级：非&gt;与&gt;或，有括号先算括号 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113174907.png">查看图片：Pasted image 20251113174907.png</a></p><h3 id="基本逻辑运算" tabindex="-1">基本逻辑运算 <a class="header-anchor" href="#基本逻辑运算" aria-label="Permalink to &quot;基本逻辑运算&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113173724.png">查看图片：Pasted image 20251113173724.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113173832.png">查看图片：Pasted image 20251113173832.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113173946.png">查看图片：Pasted image 20251113173946.png</a></p><h3 id="复合逻辑运算" tabindex="-1">复合逻辑运算 <a class="header-anchor" href="#复合逻辑运算" aria-label="Permalink to &quot;复合逻辑运算&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113174129.png">查看图片：Pasted image 20251113174129.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113174212.png">查看图片：Pasted image 20251113174212.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113174453.png">查看图片：Pasted image 20251113174453.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113174832.png">查看图片：Pasted image 20251113174832.png</a></p><h3 id="多路选择器" tabindex="-1">多路选择器 <a class="header-anchor" href="#多路选择器" aria-label="Permalink to &quot;多路选择器&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113180449.png">查看图片：Pasted image 20251113180449.png</a></p><h3 id="三态门" tabindex="-1">三态门 <a class="header-anchor" href="#三态门" aria-label="Permalink to &quot;三态门&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113180552.png">查看图片：Pasted image 20251113180552.png</a></p><h2 id="_2-2-1-加法器" tabindex="-1">2.2.1 加法器 <a class="header-anchor" href="#_2-2-1-加法器" aria-label="Permalink to &quot;2.2.1 加法器&quot;">​</a></h2><h3 id="串行进位的并行加法器" tabindex="-1">串行进位的并行加法器 <a class="header-anchor" href="#串行进位的并行加法器" aria-label="Permalink to &quot;串行进位的并行加法器&quot;">​</a></h3><p>进位信息是串行产生的，只有后一位运算完，前一位才能得到稳定的结果，这也叫行波进位 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113181258.png">查看图片：Pasted image 20251113181258.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113181417.png">查看图片：Pasted image 20251113181417.png</a></p><h3 id="并行进位的并行加法器" tabindex="-1">并行进位的并行加法器 <a class="header-anchor" href="#并行进位的并行加法器" aria-label="Permalink to &quot;并行进位的并行加法器&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113181810.png">查看图片：Pasted image 20251113181810.png</a> 无论是串行还是并行，都可以封装为一个加法器，不必关心其内部</p><h3 id="带有标志位的加法器" tabindex="-1">带有标志位的加法器 <a class="header-anchor" href="#带有标志位的加法器" aria-label="Permalink to &quot;带有标志位的加法器&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113182101.png">查看图片：Pasted image 20251113182101.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113182551.png">查看图片：Pasted image 20251113182551.png</a></p><h3 id="算数逻辑单元alu" tabindex="-1">算数逻辑单元ALU <a class="header-anchor" href="#算数逻辑单元alu" aria-label="Permalink to &quot;算数逻辑单元ALU&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113183705.png">查看图片：Pasted image 20251113183705.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113183857.png">查看图片：Pasted image 20251113183857.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113185327.png">查看图片：Pasted image 20251113185327.png</a></p><h2 id="_2-2-2-定点数的位移运算" tabindex="-1">2.2.2 定点数的位移运算 <a class="header-anchor" href="#_2-2-2-定点数的位移运算" aria-label="Permalink to &quot;2.2.2 定点数的位移运算&quot;">​</a></h2><h3 id="逻辑移位-无符号整数" tabindex="-1">逻辑移位（无符号整数） <a class="header-anchor" href="#逻辑移位-无符号整数" aria-label="Permalink to &quot;逻辑移位（无符号整数）&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113190330.png">查看图片：Pasted image 20251113190330.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113190415.png">查看图片：Pasted image 20251113190415.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113190519.png">查看图片：Pasted image 20251113190519.png</a></p><h3 id="算数移位-带符号整数-补码" tabindex="-1">算数移位（带符号整数 补码） <a class="header-anchor" href="#算数移位-带符号整数-补码" aria-label="Permalink to &quot;算数移位（带符号整数 补码）&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113190809.png">查看图片：Pasted image 20251113190809.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113190841.png">查看图片：Pasted image 20251113190841.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113191051.png">查看图片：Pasted image 20251113191051.png</a></p><h2 id="_2-2-3-定点数的加减运算" tabindex="-1">2.2.3 定点数的加减运算 <a class="header-anchor" href="#_2-2-3-定点数的加减运算" aria-label="Permalink to &quot;2.2.3 定点数的加减运算&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113192650.png">查看图片：Pasted image 20251113192650.png</a></p><p>这种方式实现很困难，一般使用补码： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113193326.png">查看图片：Pasted image 20251113193326.png</a></p><p>只有同号的两个数相加才会溢出，异号的两个数的和只能比这两个数的绝对值更小，不可能溢出： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113193900.png">查看图片：Pasted image 20251113193900.png</a></p><h3 id="溢出判断" tabindex="-1">溢出判断 <a class="header-anchor" href="#溢出判断" aria-label="Permalink to &quot;溢出判断&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113194318.png">查看图片：Pasted image 20251113194318.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113194521.png">查看图片：Pasted image 20251113194521.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251113194829.png">查看图片：Pasted image 20251113194829.png</a></p><h2 id="_2-2-4-无符号数的加减运算" tabindex="-1">2.2.4 无符号数的加减运算 <a class="header-anchor" href="#_2-2-4-无符号数的加减运算" aria-label="Permalink to &quot;2.2.4 无符号数的加减运算&quot;">​</a></h2><h3 id="回顾带符号数的加减运算" tabindex="-1">回顾带符号数的加减运算 <a class="header-anchor" href="#回顾带符号数的加减运算" aria-label="Permalink to &quot;回顾带符号数的加减运算&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123161611.png">查看图片：Pasted image 20251123161611.png</a></p><h3 id="无符号数的加法运算" tabindex="-1">无符号数的加法运算 <a class="header-anchor" href="#无符号数的加法运算" aria-label="Permalink to &quot;无符号数的加法运算&quot;">​</a></h3><p>与有符号数的加法运算是一样的： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123162143.png">查看图片：Pasted image 20251123162143.png</a></p><h3 id="无符号数的减法运算" tabindex="-1">无符号数的减法运算 <a class="header-anchor" href="#无符号数的减法运算" aria-label="Permalink to &quot;无符号数的减法运算&quot;">​</a></h3><p>与有符号数的减法运算是一样的： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123162427.png">查看图片：Pasted image 20251123162427.png</a></p><h3 id="溢出判断-1" tabindex="-1">溢出判断 <a class="header-anchor" href="#溢出判断-1" aria-label="Permalink to &quot;溢出判断&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123162645.png">查看图片：Pasted image 20251123162645.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123162908.png">查看图片：Pasted image 20251123162908.png</a></p><h3 id="电路实现补码加减运算" tabindex="-1">电路实现补码加减运算 <a class="header-anchor" href="#电路实现补码加减运算" aria-label="Permalink to &quot;电路实现补码加减运算&quot;">​</a></h3><p>参考本章：带有标志位的加法器中的标志位的生成原理 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123163823.png">查看图片：Pasted image 20251123163823.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123164318.png">查看图片：Pasted image 20251123164318.png</a></p><h2 id="_2-2-5-无符号与带符号整数乘除法" tabindex="-1">2.2.5 无符号与带符号整数乘除法 <a class="header-anchor" href="#_2-2-5-无符号与带符号整数乘除法" aria-label="Permalink to &quot;2.2.5 无符号与带符号整数乘除法&quot;">​</a></h2><h3 id="无符号整数乘法" tabindex="-1">无符号整数乘法 <a class="header-anchor" href="#无符号整数乘法" aria-label="Permalink to &quot;无符号整数乘法&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123165438.png">查看图片：Pasted image 20251123165438.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123165729.png">查看图片：Pasted image 20251123165729.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123170110.png">查看图片：Pasted image 20251123170110.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123170240.png">查看图片：Pasted image 20251123170240.png</a></p><h5 id="溢出判断-2" tabindex="-1">溢出判断 <a class="header-anchor" href="#溢出判断-2" aria-label="Permalink to &quot;溢出判断&quot;">​</a></h5><p>在大部分计算机中，n bit的数相乘依旧为n bit，这就可能会发生溢出 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123170811.png">查看图片：Pasted image 20251123170811.png</a></p><h3 id="带符号数乘法" tabindex="-1">带符号数乘法 <a class="header-anchor" href="#带符号数乘法" aria-label="Permalink to &quot;带符号数乘法&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123172354.png">查看图片：Pasted image 20251123172354.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123172729.png">查看图片：Pasted image 20251123172729.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123172857.png">查看图片：Pasted image 20251123172857.png</a></p><h5 id="溢出判断-3" tabindex="-1">溢出判断 <a class="header-anchor" href="#溢出判断-3" aria-label="Permalink to &quot;溢出判断&quot;">​</a></h5><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251123173952.png">查看图片：Pasted image 20251123173952.png</a> 对于1110 1110 就查看1110 1 这n+1个bit是否完全相同</p><h3 id="计算机实现乘法的三种方式" tabindex="-1">计算机实现乘法的三种方式 <a class="header-anchor" href="#计算机实现乘法的三种方式" aria-label="Permalink to &quot;计算机实现乘法的三种方式&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129141037.png">查看图片：Pasted image 20251129141037.png</a></p><h5 id="两位乘法" tabindex="-1">两位乘法 <a class="header-anchor" href="#两位乘法" aria-label="Permalink to &quot;两位乘法&quot;">​</a></h5><p>每轮（也就是在同样的时钟周期）中处理末尾的2bit，原先使用n个时钟的情况下的乘法，现在可以使用n/2个时钟处理完。</p><h5 id="阵列乘法器" tabindex="-1">阵列乘法器 <a class="header-anchor" href="#阵列乘法器" aria-label="Permalink to &quot;阵列乘法器&quot;">​</a></h5><p>使用更多的硬件，就可以减少时钟周期（不需要掌握电路原理） <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129135937.png">查看图片：Pasted image 20251129135937.png</a></p><h5 id="逻辑运算、加减运算等效实现" tabindex="-1">逻辑运算、加减运算等效实现 <a class="header-anchor" href="#逻辑运算、加减运算等效实现" aria-label="Permalink to &quot;逻辑运算、加减运算等效实现&quot;">​</a></h5><p>可以使用软件的形式实现乘法，不过其速度很慢 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129140234.png">查看图片：Pasted image 20251129140234.png</a></p><h3 id="无符号整数的除法" tabindex="-1">无符号整数的除法 <a class="header-anchor" href="#无符号整数的除法" aria-label="Permalink to &quot;无符号整数的除法&quot;">​</a></h3><h5 id="手算" tabindex="-1">手算 <a class="header-anchor" href="#手算" aria-label="Permalink to &quot;手算&quot;">​</a></h5><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129142302.png">查看图片：Pasted image 20251129142302.png</a></p><h5 id="除法电路" tabindex="-1">除法电路 <a class="header-anchor" href="#除法电路" aria-label="Permalink to &quot;除法电路&quot;">​</a></h5><p>重点关注开始状态、结束状态以及异常，中间细节可以放缓 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129142932.png">查看图片：Pasted image 20251129142932.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129143324.png">查看图片：Pasted image 20251129143324.png</a> 这里使用的是回复余数法，同时也有不恢复的方式</p><h5 id="商溢出" tabindex="-1">商溢出 <a class="header-anchor" href="#商溢出" aria-label="Permalink to &quot;商溢出&quot;">​</a></h5><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129154221.png">查看图片：Pasted image 20251129154221.png</a></p><h1 id="_2-3-浮点数" tabindex="-1">2.3 浮点数 <a class="header-anchor" href="#_2-3-浮点数" aria-label="Permalink to &quot;2.3 浮点数&quot;">​</a></h1><p>在考研中，仅考察IEEE 754的规则，其他规则并不考察。并且考研中，浮点数进关注加减法，不关注乘除法</p><h2 id="_2-3-1-ieee-754-标准浮点数" tabindex="-1">2.3.1 IEEE 754 标准浮点数 <a class="header-anchor" href="#_2-3-1-ieee-754-标准浮点数" aria-label="Permalink to &quot;2.3.1 IEEE 754 标准浮点数&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129160505.png">查看图片：Pasted image 20251129160505.png</a></p><p>由于计算机的机器字长是有限的，对于一个超大数据，我们不可能一直扩展其位数长度，我们可以将其中的一部分舍去（数据精度丢失），以用更少的bit存储，同时对于整体的影响并不太大。 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129161709.png">查看图片：Pasted image 20251129161709.png</a></p><p>位数的位数决定了表示的数的精度，阶码表示数值表示的范围的大小，在计算机中基数默认是2： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129161827.png">查看图片：Pasted image 20251129161827.png</a></p><h5 id="float" tabindex="-1">float <a class="header-anchor" href="#float" aria-label="Permalink to &quot;float&quot;">​</a></h5><p>由于规格化的位数，它一定会有一个1在首位，所以我们隐含的默认它，将这一位用于存储更低位的位数。阶码，表示小数点的向前向后的移动，使用移码存储： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129162408.png">查看图片：Pasted image 20251129162408.png</a></p><h5 id="double" tabindex="-1">double <a class="header-anchor" href="#double" aria-label="Permalink to &quot;double&quot;">​</a></h5><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129163021.png">查看图片：Pasted image 20251129163021.png</a></p><h2 id="_2-3-2-浮点数的表示范围" tabindex="-1">2.3.2 浮点数的表示范围 <a class="header-anchor" href="#_2-3-2-浮点数的表示范围" aria-label="Permalink to &quot;2.3.2 浮点数的表示范围&quot;">​</a></h2><h5 id="特殊转态浮点数" tabindex="-1">特殊转态浮点数 <a class="header-anchor" href="#特殊转态浮点数" aria-label="Permalink to &quot;特殊转态浮点数&quot;">​</a></h5><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129164324.png">查看图片：Pasted image 20251129164324.png</a></p><h5 id="表示范围" tabindex="-1">表示范围 <a class="header-anchor" href="#表示范围" aria-label="Permalink to &quot;表示范围&quot;">​</a></h5><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129165226.png">查看图片：Pasted image 20251129165226.png</a></p><h5 id="溢出" tabindex="-1">溢出 <a class="header-anchor" href="#溢出" aria-label="Permalink to &quot;溢出&quot;">​</a></h5><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129165652.png">查看图片：Pasted image 20251129165652.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129165950.png">查看图片：Pasted image 20251129165950.png</a> IEEE 规定浮点数溢出不会导致程序的中断</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129165810.png">查看图片：Pasted image 20251129165810.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129170527.png">查看图片：Pasted image 20251129170527.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129170616.png">查看图片：Pasted image 20251129170616.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129171016.png">查看图片：Pasted image 20251129171016.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129171438.png">查看图片：Pasted image 20251129171438.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129172115.png">查看图片：Pasted image 20251129172115.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129172137.png">查看图片：Pasted image 20251129172137.png</a></p><h2 id="_2-3-3-数据的存储和排列" tabindex="-1">2.3.3 数据的存储和排列 <a class="header-anchor" href="#_2-3-3-数据的存储和排列" aria-label="Permalink to &quot;2.3.3 数据的存储和排列&quot;">​</a></h2><p>这里B站的视频少了几节？</p><h5 id="大小端模式" tabindex="-1">大小端模式 <a class="header-anchor" href="#大小端模式" aria-label="Permalink to &quot;大小端模式&quot;">​</a></h5><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129172804.png">查看图片：Pasted image 20251129172804.png</a></p><h5 id="边界对齐" tabindex="-1">边界对齐 <a class="header-anchor" href="#边界对齐" aria-label="Permalink to &quot;边界对齐&quot;">​</a></h5><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251129173953.png">查看图片：Pasted image 20251129173953.png</a></p>',144)])])}const P=e(n,[["render",r]]);export{l as __pageData,P as default};
